// API Key authentication check - timing-safe comparison
const headers = $input.first().json.headers || {};

// Case-insensitive header lookup (defense against platform normalization changes)
const headerKeys = Object.keys(headers);
const apiKeyHeader = headerKeys.find(k => k.toLowerCase() === 'x-api-key');
const providedKey = apiKeyHeader ? headers[apiKeyHeader] : '';
const expectedKey = $env.RVC_API_KEY;

// Timing-safe comparison - constant time regardless of input length
// Prevents timing oracle attacks by ensuring comparison takes same time for all inputs
function timingSafeEqual(a, b) {
  if (typeof a !== 'string' || typeof b !== 'string') return false;

  const MAX_LEN = 256;
  // Normalize both to exactly MAX_LEN characters (truncate or pad with \0)
  const aPadded = a.slice(0, MAX_LEN).padEnd(MAX_LEN, '\0');
  const bPadded = b.slice(0, MAX_LEN).padEnd(MAX_LEN, '\0');

  let result = 0;
  // Constant-time comparison: always iterate MAX_LEN, no early returns
  for (let i = 0; i < MAX_LEN; i++) {
    result |= aPadded.charCodeAt(i) ^ bPadded.charCodeAt(i);
  }
  // Include original length check in constant-time result
  result |= (a.length === b.length) ? 0 : 1;
  return result === 0;
}

// Authentication logic:
// - If server has expectedKey configured: client MUST provide matching key
// - If client provides a key but server has none: reject (unauthorized)
// - If neither configured: allow
if ((expectedKey || providedKey) && !timingSafeEqual(providedKey || '', expectedKey || '')) {
  return [{ json: { valid: false, error: 'Authentication failed' } }];
}

const input = $input.first().json || {};
const model = input.model;
const audioPath = input.audio_path || '';
const audio = input.audio || '';
const channel = input.channel;
const f0MethodInput = input.f0_method;
const pitchInput = input.pitch;

// === MODEL VALIDATION ===
if (typeof model !== 'string' || !model) {
  return [{ json: { valid: false, error: 'Missing required field: model (must be a string)' } }];
}
const validModelPattern = /^[a-zA-Z0-9._-]+$/;
if (!validModelPattern.test(model)) {
  return [{ json: { valid: false, error: 'Invalid model name: must be alphanumeric, dot, dash, or underscore only' } }];
}
if (model.length > 100) {
  return [{ json: { valid: false, error: 'Model name too long: max 100 characters' } }];
}

// === REQUIRED FIELD CHECKS ===
if (!audio && !audioPath) {
  return [{ json: { valid: false, error: 'Missing required field: audio or audio_path' } }];
}

// === ENHANCED PATH TRAVERSAL PROTECTION ===
// Blocks: ../, ..\, %2e%2e%2f, %252e%252e%252f, %2f, %252f, null bytes, absolute paths, Windows drive letters
const pathTraversalPattern = /(\.\.[/\\]|%2e%2e[/\\]|%252e%252e[/\\]|%2[fF]|%252[fF]|%00|\x00|^\/|^[a-zA-Z]:\\)/i;

// Decode and normalize for Unicode NFC attack detection
let normalizedPath;
try {
  normalizedPath = decodeURIComponent(audioPath).normalize('NFC');
} catch (e) {
  return [{ json: { valid: false, error: 'Invalid audio_path: malformed URL encoding' } }];
}

// === PATH VALIDATION ===
if (audioPath) {
  if (pathTraversalPattern.test(audioPath) || pathTraversalPattern.test(normalizedPath)) {
  return [{ json: { valid: false, error: 'Path traversal detected: audio_path contains invalid sequences' } }];
  }
}

// === CHANNEL VALIDATION ===
// Strip # prefix and Discord special chars, then validate clean name
const channelStr = typeof channel === 'string' ? channel : 'general';
const channelRaw = channelStr.replace(/^#+/, '').replace(/[<>@&]/g, '').slice(0, 100);
if (!channelRaw.match(/^[a-zA-Z0-9_-]+$/)) {
  return [{ json: { valid: false, error: 'Invalid channel: must be alphanumeric, dash, or underscore only' } }];
}

// === F0_METHOD ALLOWLIST ===
const validF0Methods = ['harvest', 'pm', 'dio', 'rmvpe', 'crepe', 'crepe-tiny', 'mangio-crepe', 'mangio-crepe-tiny'];
const f0MethodStr = typeof f0MethodInput === 'string' ? f0MethodInput : 'rmvpe';
const f0Method = f0MethodStr.toLowerCase();
if (!validF0Methods.includes(f0Method)) {
  return [{ json: { valid: false, error: 'Invalid f0_method: must be one of ' + validF0Methods.join(', ') } }];
}

// === PITCH VALIDATION ===
const pitchRaw = parseInt(pitchInput ?? 0, 10);
if (isNaN(pitchRaw) || pitchRaw < -12 || pitchRaw > 12) {
  return [{ json: { valid: false, error: 'Invalid pitch: must be a number between -12 and +12 semitones' } }];
}
const pitch = pitchRaw;

return [{
  json: {
    valid: true,
    model: model,
    audio: audio,
    audio_path: audioPath,
    channel: channelRaw,
    pitch: pitch,
    f0_method: f0Method
  }
}];

// Validate upload response path
const uploadResponse = $input.first().json || {};
const path = uploadResponse.path || '';

// Must have a path from upload - no fallback to user input
if (!path) {
  return [{ json: { valid: false, error: 'No audio path returned from upload service' } }];
}

// Decode and validate the path
let decodedPath;
try {
  decodedPath = decodeURIComponent(path).normalize('NFC');
} catch (e) {
  return [{ json: { valid: false, error: 'Invalid upload path: malformed URL encoding' } }];
}

// Strict validation: must be /tmp/<alphanumeric>.<audio_ext>
const validPathPattern = /^\/tmp\/[a-zA-Z0-9_-]+\.(wav|mp3|ogg|flac|webm)$/i;

// Path traversal check with URL-encoded variants
const traversalPattern = /(\.\.[/\\]|%2e%2e%2[fF]|%252e%252e%252[fF]|%2[fF]|%252[fF]|%00)/i;

// Check for traversal in both raw and decoded path
if (traversalPattern.test(path) || traversalPattern.test(decodedPath) || !validPathPattern.test(decodedPath)) {
  return [{ json: { valid: false, error: 'Invalid upload response path: failed validation' } }];
}

return [{ json: { valid: true, path: path, from_upload: true } }];

